const forbiddenRawFields = ['raw_message','message','message_text','private_text','chat_text','transcript','screenshot','conversation','raw_chat','raw_text'];
const forbiddenPhrases = ['they like you','hidden intent','they are lying','this proves','diagnose','manipulate','make them respond','win them back'];
const input = $json.body || $json;
const clean = {};
let rawTextRemoved = false;
for (const [key, value] of Object.entries(input)) {
  if (forbiddenRawFields.includes(key)) {
    rawTextRemoved = true;
    continue;
  }
  clean[key] = value;
}
const textForReview = JSON.stringify(clean).toLowerCase();
const blockedPhraseHit = forbiddenPhrases.find((phrase) => textForReview.includes(phrase)) || null;
let route = 'product_feedback';
if (blockedPhraseHit || clean.feedback_category === 'unsafe_wording' || clean.severity === 'high') route = 'safety_review';
else if (clean.event_type === 'backend_failure') route = 'reliability_queue';
else if (clean.feedback_category === 'bug') route = 'bug_queue';
return [{ json: { ...clean, route, raw_text_removed: rawTextRemoved || clean.raw_message_present === false, blocked_phrase_hit: blockedPhraseHit, processed_at: new Date().toISOString() } }];

const event = $('Code - Sanitize + Route').first().json;
const health = $json || {};
return [{ json: { timestamp: event.processed_at, source: event.source || null, event_type: event.event_type || null, result_id: event.result_id || null, cue_type: event.cue_type || null, feedback_category: event.feedback_category || null, severity: event.severity || null, route: event.route || 'product_feedback', raw_text_removed: event.raw_text_removed === true, backend_status: health.ok === true ? 'ok' : 'unknown_or_failed', notes: event.notes || null, blocked_phrase_hit: event.blocked_phrase_hit || null } }];
